class TestRuleMode:
    def test_build_and_get_result(self):
        """规则模式基本训练和提取"""
        scraper = AutoScraper()
        wanted_dict = {
            "file_name": [".gitattributes", "config.json"],
        }
        result = scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict)
        # build 应该返回结果（可能是 dict 或 list）
        assert result is not None

    def test_get_result_similar(self):
        """规则模式跨页面泛化（规则模式在结构差异大的页面可能为空）"""
        scraper = AutoScraper()
        wanted_dict = {
            "file_name": [".gitattributes", "config.json"],
        }
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict)

        result = scraper.get_result_similar(
            html=FILE_LIST_HTML_2, group_by_alias=True
        )
        # 规则模式返回 dict（可能为空，取决于 HTML 结构是否匹配）
        assert isinstance(result, (dict, list))


class TestMLMode:
    """测试 ML 增强模式（需要 sklearn）"""

    @pytest.fixture
    def ml_available(self):
        try:
            import sklearn
            return True
        except ImportError:
            return False

    def test_ml_build_text_field(self, ml_available):
        """ML 模式可以训练文本字段"""
        if not ml_available:
            pytest.skip("sklearn not installed")

        scraper = AutoScraper()
        wanted_dict = {
            "file_name": [".gitattributes", "config.json"],
        }
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict, use_ml=True)

        if scraper._ml_active:
            result = scraper.get_result_similar(
                html=FILE_LIST_HTML, group_by_alias=True
            )
            assert isinstance(result, dict)
            if "file_name" in result:
                assert len(result["file_name"]) >= 2

    def test_ml_url_field_extracts_href(self, ml_available):
        """Bug 1 修复验证：URL 字段应提取 href 而非文本"""
        if not ml_available:
            pytest.skip("sklearn not installed")

        scraper = AutoScraper()
        wanted_dict = {
            "download_url": [
                "/datasets/org/repo/resolve/main/.gitattributes",
                "/datasets/org/repo/resolve/main/config.json",
            ],
        }
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict, use_ml=True)

        if scraper._ml_active and scraper._ml_classifiers:
            result = scraper.get_result_similar(
                html=FILE_LIST_HTML, group_by_alias=True
            )
            if "download_url" in result and result["download_url"]:
                # 应该包含 href 路径，而非纯文本
                for val in result["download_url"]:
                    assert "/" in val, f"Expected URL path, got: {val}"

    def test_ml_full_url_matches_relative_path(self, ml_available):
        """Bug 2 修复验证：完整 URL 样本应匹配 HTML 中的相对路径"""
        if not ml_available:
            pytest.skip("sklearn not installed")

        scraper = AutoScraper()
        # 用完整 URL 作为样本（用户常见场景）
        wanted_dict = {
            "download_url": [
                "https://huggingface.co/datasets/org/repo/resolve/main/.gitattributes",
                "https://huggingface.co/datasets/org/repo/resolve/main/config.json",
            ],
        }
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict, use_ml=True)

        if scraper._ml_active:
            # 关键：应该能找到正样本（之前的 bug 会导致 "未找到正样本，跳过"）
            assert "download_url" in scraper._ml_classifiers, \
                "ML should find positive samples with full URL → relative path matching"

    def test_ml_wanted_dict_stored(self, ml_available):
        """训练后 _ml_wanted_dict 应被保存"""
        if not ml_available:
            pytest.skip("sklearn not installed")

        scraper = AutoScraper()
        wanted_dict = {"name": ["config.json"]}
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict, use_ml=True)

        if scraper._ml_active:
            assert hasattr(scraper, '_ml_wanted_dict')
            assert scraper._ml_wanted_dict == wanted_dict

    def test_ml_cross_page(self, ml_available):
        """ML 在不同页面上的泛化能力"""
        if not ml_available:
            pytest.skip("sklearn not installed")

        scraper = AutoScraper()
        wanted_dict = {
            "file_name": [".gitattributes", "config.json"],
        }
        scraper.build(html=FILE_LIST_HTML, wanted_dict=wanted_dict, use_ml=True)

        if scraper._ml_active and scraper._ml_classifiers:
            result = scraper.get_result_similar(
                html=FILE_LIST_HTML_2, group_by_alias=True
            )
            if "file_name" in result:
                # 应能在新页面提取文件名
                assert len(result["file_name"]) >= 1


class TestNodeSignature:
    def test_same_structure_same_sig(self):
        html = "<ul><li class='item'>A</li><li class='item'>B</li></ul>"
        soup = BeautifulSoup(html, "html.parser")
        scraper = AutoScraper()
        lis = soup.find_all("li")
        sig0 = scraper._node_signature(lis[0])
        sig1 = scraper._node_signature(lis[1])
        assert sig0 == sig1

    def test_different_structure_different_sig(self):
        html = "<div><span class='a'>X</span><p class='b'>Y</p></div>"
        soup = BeautifulSoup(html, "html.parser")
        scraper = AutoScraper()
        span = soup.find("span")
        p = soup.find("p")
        assert scraper._node_signature(span) != scraper._node_signature(p)


class TestHybridMode:
    def test_build_with_mixed_fields(self):
        """混合字段：文本 + URL"""
        scraper = AutoScraper()
        wanted_dict = {
            "link": ["/David-patrick-chuks","/wael-benslimen"],
        }

        result = scraper.build(url="https://github.com/David-patrick-chuks/Riona-AI-Agent", wanted_dict=wanted_dict)
        # 至少应该返回非 None
        print(scraper.get_result_similar(url="https://github.com/LeoChen-CoreMind/VMPacker",group_by_alias=True))
        assert result is not None or scraper._ml_active
